function LDreamTripUnitView:OnUpdate(deltaTime)
    if self._isDisposed then return end
    --- 更新
    if self:IsMainRole() then
        self:RunMainRoleUpdate(deltaTime)
    else
        self:RunOtherRoleUpdate(deltaTime)
    end
end

function LDreamTripUnitView:RunMainRoleUpdate(deltaTime)
    if not self._moveTime then
        if #self._runPosList > 0 then
            local runPosInfo = table.remove(self._runPosList,1)
            self._runPosInfo = runPosInfo
            local pos = runPosInfo.pos
            self._moveTime = self:GetMoveTime(pos)
            self:DoMoveTo(pos,self._moveTime)
            local isEmpty = #self._runPosList < 1
            if self._view then
                self._view:PlayPassGridRootAni(runPosInfo.idx,self._moveTime,isEmpty,runPosInfo)
            end
        end
    end
    if self._moveTime then
        if self._moveTime < 0 then
            self._moveTime = nil
            if #self._runPosList < 1 then
                local runCallBack = self._runCallBack
                self._runCallBack = nil
                if runCallBack then runCallBack() end
                self:StopMove()
                local runPosInfo = self._runPosInfo
                if runPosInfo and runPosInfo.moveState == DreamTripMoveType.MoveEnd then
                else
                    CtrlCenter.DreamTrip:ExecuteClick()
                end
                self._runPosInfo = nil
            end
        else
            self._moveTime = self._moveTime - deltaTime
        end
    end
end

function LDreamTripUnitView:RunOtherRoleUpdate(deltaTime)

end
------------------------------------------ 更新 End


function LDreamTripUnitView:LoadUnitView()
    self._gameObjMap = {}
    --if self._modelDp then
    --    self._modelDp:Dispose()
    --end
    if self._spineDp then
        self._spineDp:Dispose()
    end
    self:ClearEffectMap()
    self:ClearSpriteMap()

    local unitData = self._unitData
    local modelRoot = self:CreateGameObj(GameObjEnum.ModelRoot,"unitHero-" .. unitData.gameObjName)
    local modelRootTrans = modelRoot.transform
    modelRootTrans:SetParent(self._rootNodeTrans, false)
    modelRootTrans.localScale = Vector3.zero
    local pos = unitData.pos
    modelRootTrans.localPosition = Vector3(pos.x,pos.y,pos.z)
    modelRootTrans.localRotation = Quaternion.identity


    local showType = self._showType
    if showType == DreamTripShowType.ShowModel then
        self:_onLoadModelDp()
    elseif showType == DreamTripShowType.ShowPic or showType == DreamTripShowType.ShowTPic then
        self:_onLoadShowPic(modelRoot,modelRootTrans,unitData.model,SpriteEnum.Main)
        if showType == DreamTripShowType.ShowTPic then
            self:_onLoadTPicEff(modelRoot,modelRootTrans)
        end
    elseif showType == DreamTripShowType.ShowEff then
        self:_onLoadShowEff()
    end

    self:LoadTarget()

    if self:IsMainRole() then
        self:Forward(unitData.pos)
        local cRole = modelRoot:GetComponent(typeOfRoleObject)
        if cRole == nil then cRole = modelRoot:AddComponent(typeOfRoleObject) end
        self._cRoleObj = cRole
        cRole.isPause = false
        cRole.isMoving = false
        cRole.isDirectMove = false
        cRole.OnMoveEnd = function()
            if self._moveEndFun then
                self._moveEndFun()
                return
            end
            --self:StopMove()
        end
    end
end

