function LDreamTripUnitView:_onLoadModelDp()
    local unitData = self._unitData
    local modelRootTrans = self:GetModelRootTrans()
    local spineDp = require("LApp.component.dp.LxSpineDp"):new()
    self._spineDp = spineDp
    spineDp:InitDp(unitData.model,modelRootTrans)
    spineDp:SetLocalPosition(Vector3.zero)
    spineDp:SetScale(modelDpSize)
    spineDp:SetEulerAngles(Vector3(0,-180,0))
    spineDp:SetLoadedCallback(function(modelDp)
        self:DoModelRootAni(modelRootTrans)
        self:OnLoadModel(modelDp)
    end)
    spineDp:Load()

--[[    local modelDp = require("LApp.component.dp.LxModelDp"):new()
    modelDp:InitDp(unitData.model, modelRootTrans)
    modelDp:SetLocalPosition(Vector3.zero)
    modelDp:SetScale(Vector3(modelDpSize,modelDpSize,modelDpSize))
    modelDp:SetEulerAngles(Vector3(0,-180,0))
    modelDp:SetLoadedCallback(function(modelDp)
        self:DoModelRootAni(modelRootTrans)
        self:OnLoadModel(modelDp)
    end)
    modelDp:Load()
    self._modelDp = modelDp]]
end

function LDreamTripUnitView:_onLoadShowPic(modelRootObj,modelRootTrans,model,spriteEnum)
    self:CreateSprite(modelRootObj,modelRootTrans,model,spriteEnum)
end

function LDreamTripUnitView:_onLoadTPicEff(modelRootObj,modelRootTrans)
    self:CreateEffect("tuitu_jiangliguangxiao", modelRootTrans,ModelEffEnum.PicResident)
end

function LDreamTripUnitView:_onLoadShowEff()
    local unitData = self._unitData
    local modelRootTrans = self:GetModelRootTrans()
    modelRootTrans.localScale = unitData.modelScale
    local modelList = string.split(unitData.model,"|")
    local gameObjName = unitData.gameObjName
    for i,v in ipairs(modelList) do
        local effGameObj = self:CreateGameObj(i,"unitEffect-" .. gameObjName)
        ShowObject(effGameObj,false)
        local effGameTrans = effGameObj.transform
        effGameTrans:SetParent(modelRootTrans, false)
        effGameTrans.localScale = Vector3.one
        effGameTrans.localPosition = Vector3.zero
        effGameTrans.localRotation = Quaternion.identity

        local isMain = i == ModelEffEnum.Main
        self:CreateEffect(v, effGameTrans,i,function(dp)
            if isMain then
                ShowObject(effGameObj,true)
                self:DoModelRootAni(effGameTrans)
            end
        end)
    end
end
------------------------------------ Load End

function LDreamTripUnitView:DoModelRootAni(modelRootTrans)
    if not modelRootTrans then return end
    local unitData = self._unitData
    local index = unitData.index
    local modelScale = unitData.modelScale
    if index then
        local curIdx = CtrlCenter.DreamTrip:GetDreamTripFinalPoint()
        local isShow = curIdx ~= index
        self:ShowModelDp(isShow)
        if not isShow then
            modelRootTrans.localScale = modelScale
            return
        end
    end
    if self._view then
        if modelRootTrans and modelRootTrans.gameObject and not IsNull(modelRootTrans.gameObject) then
            local tween = self._view:NewTweenSeq(modelRootTrans.gameObject,function()
                modelRootTrans.localScale = modelScale

                self:DoUnitViewAni()
            end)
            tween:Append(modelRootTrans:DOScale(modelScale, 0.5):SetEase(TweenEase.OutQuad))
            tween:PlayForward()
        end
    else
        modelRootTrans.localScale = modelScale
    end
end

---@param modelDp LxSpineDp
function LDreamTripUnitView:OnLoadModel(modelDp)
    local unitData = self._unitData
    if unitData and unitData.callBack then
        unitData.callBack(self)
    end
    if self._loadCallback then
        self._loadCallback(self)
    end
    self._modelAniMap = {}
    local aniList = modelDp:GetAniNameStrList()
    for i, v in ipairs(aniList) do
        self._modelAniMap[v] = true
    end
    self:PlayIdle()
end

function LDreamTripUnitView:PlayIdle()
    if not self._spineDp then return end
    local aniName = "idle1"
    if not self._modelAniMap[aniName] then
        aniName = "idle"
    end
    self._spineDp:PlayAni(aniName,true,false)
--[[    if not self._modelDp then return end
    if self._modelAniMap['idle1'] then
        self._modelDp:PlayAni('idle1')
    else
        self._modelDp:PlayAni('idle')
    end]]
end

function LDreamTripUnitView:LoadTarget()
    local unitData = self._unitData
    if not unitData then return end

    ---@type LDreamTripUnitTargetData
    local targetData = unitData.targetData
    if not targetData then return end

    local targetObj = self:CreateGameObj(GameObjEnum.BossTarget,unitData.gameObjName)
    local targetObjTrans = targetObj.transform
    targetObjTrans:SetParent(self._rootNodeTrans, false)
    targetObjTrans.localScale = Vector3.zero

    local targetPos = targetData.targetPos
    targetObjTrans.localPosition = Vector3(targetPos.x,targetPos.y,targetPos.z)
    targetObjTrans.localRotation = Quaternion.identity

    local targetType = targetData.targetType
    if targetType == DreamTripShowType.ShowModel then
    elseif targetType == DreamTripShowType.ShowPic or targetType == DreamTripShowType.ShowTPic then
        self:_onLoadShowPic(targetObj,targetObjTrans,targetData.targetModel,SpriteEnum.Target)
    elseif targetType == DreamTripShowType.ShowEff then
        self:CreateEffect(targetData.targetModel, targetObjTrans,ModelEffEnum.Target,function(dp)
            self:DoModelRootAni(targetObjTrans)
        end)
    end
end

function LDreamTripUnitView:StopMove()
    self._modelState = DreamTripPlayerRoleState.Idle
    self:PlayIdle()
end

function LDreamTripUnitView:DirectMove(directPos)
    self._modelState = DreamTripPlayerRoleState.Run
    --self._modelDp:PlayAni("run")
    self._spineDp:PlayAni("run",true,false)
    local curPos = self:GetPosition()
    self:Forward(directPos - curPos,curPos,directPos)
    self:SetPosition(directPos)
end

function LDreamTripUnitView:Forward(dirPos,curPos,newPos)
    local dir = Vector2.Normalize(dirPos)
    if dir.magnitude > 0 then
        local showType = self._showType
        if showType == DreamTripShowType.ShowModel then
            if curPos and newPos then
                local bFilp = curPos.x - newPos.x > 0
                self._spineDp:SetFlipX(bFilp)
            else
                --self._modelDp:SetForward(Vector3(dir.x, 0, dir.y))
                self._spineDp:SetForward(Vector3(dir.x, 0, dir.y))
            end
        elseif showType == DreamTripShowType.ShowPic then
        elseif showType == DreamTripShowType.ShowEff then
            local modelEff = self:GetMainModelEff()
            if modelEff then
                modelEff:SetForward(Vector3(dir.x, 0, dir.y))
            end
        end
    end
end

function LDreamTripUnitView:SetPosition(pos)
    self:GetModelRootTrans().localPosition = pos
end

---@return LxSpineDp
function LDreamTripUnitView:GetModelDp()
    return self._spineDp
