function LDreamTripUnitView:Move(pos)
    pos.z = 0
    local time = self:GetMoveTime(pos)
    self:DoMoveTo(pos, time)
end

function LDreamTripUnitView:GetMoveTime(pos)
    local speed = self._unitData.speed
    local dis = Vector2.Distance(self:GetPosition(), pos)
    return dis / speed
end

function LDreamTripUnitView:DoMoveTo(pos, time)
    if not self._cRoleObj then return end

    local obj = self._cRoleObj
    obj.moveType = 0
    if not obj.isMoving then
        obj.isDirectMove = false
        obj.isIgnoreZ = true
        obj.isMoving = true
        --self._modelDp:PlayAni("run")
        self._spineDp:PlayAni("run",true,false)
        self._modelState = DreamTripPlayerRoleState.Run
    end
    obj:MoveTo(pos, time, 0)
    self:GetModelRootTrans()
    local curPos = self:GetPosition()
    self:Forward(pos - curPos,curPos,pos)
end

function LDreamTripUnitView:IsMainRole()
    return self:GetType() == DreamTripPlayerType.MainRole
end

function LDreamTripUnitView:GetUnitViewState()
    return self._modelState
end

function LDreamTripUnitView:CheckIsIdle()
    return self:GetUnitViewState() == DreamTripPlayerRoleState.Idle
end

function LDreamTripUnitView:ShowModelDp(bShow)
    local isFinish = false
    local pointObj = self._unitData and self._unitData.pointObj
    if pointObj and pointObj.finish then
        bShow = false
        isFinish = true
    end
    if self._showType == DreamTripShowType.ShowModel then
        ---@type LxModelDp
        local modelDp = self:GetModelDp()
        if modelDp and not modelDp:IsNull() then
            local dpObj = modelDp:GetDpGo()
            ShowObject(dpObj,bShow)
        end
    elseif self._showType == DreamTripShowType.ShowPic or self._showType == DreamTripShowType.ShowTPic then
        ShowObject(self:GetModelRoot(),bShow)
        local mainSprite = self:GetMainSprite()
        if mainSprite then mainSprite:Enable(bShow) end
    elseif self._showType == DreamTripShowType.ShowEff then
        local modelEff = self:GetMainModelEff()
        if modelEff and not modelEff:IsNull() then
            local dpObj = modelEff:GetDpGo()
            ShowObject(dpObj,bShow)
        end
    end
    local targetSprite = self:GetTargetSprite()
    if targetSprite then targetSprite:Enable(not isFinish) end
    local targetEff = self:GetModelEffByKey(ModelEffEnum.Target)
    if targetEff then
        local dpObj = targetEff:GetDpGo()
        ShowObject(dpObj,bShow)
    end
end

function LDreamTripUnitView:DoUnitViewAni()
    local showType = self._showType
    if showType == DreamTripShowType.ShowTPic then
        self:DoSuspend()
    end
end

function LDreamTripUnitView:DoSuspend()
    local modelRoot = self:GetModelRoot()
    if not IsValid(modelRoot) then return end
    local modelRootTrans = modelRoot.transform
    if not IsValid(modelRootTrans) then return end
    local tween = self._view:NewTweenSeq(modelRoot)
    local curVec = modelRootTrans.localPosition
    local time = CtrlCenter.DreamTrip:GetGmPicTime() or 3
    local hight = CtrlCenter.DreamTrip:GetGmPicHight() or 0.3
    local vecY = curVec.y
    tween:Append(modelRootTrans:DOLocalMoveY(vecY + hight,time)):SetEase(TweenEase.Linear)
    tween:AppendInterval(0.1)
    tween:Append(modelRootTrans:DOLocalMoveY(vecY,time)):SetEase(TweenEase.Linear)
    tween:AppendInterval(0.1)
    tween:SetLoops(-1, TweenLoopType.Restart)
    tween:PlayForward()
end

function LDreamTripUnitView:UpdateUnitData()
    if not self._unitData then return end
    local pointObj = self._unitData.pointObj
    if not pointObj then return end
    local newPointObj = ModuleCenter.Instance:GetInstancePointObj(pointObj.mapRefId,pointObj)
    self._unitData.pointObj = newPointObj
end

