function LDreamTripUnitView:CreateEffect(effName,effTrans,effectEnum,callBackFunc)
    local modelEff = require("LApp.component.dp.LxEffectDp"):new()
    modelEff:InitDp(effName, effTrans)
    modelEff:SetLoadedCallback(function(dp)
        if callBackFunc then callBackFunc(dp) end
    end)
    modelEff:Load()
    modelEff:SetScale(1)
    modelEff:SetLocalPosition(Vector3.zero)
    self._modelEffMap[effectEnum] = modelEff
end

---@return LxEffectDp
function LDreamTripUnitView:GetMainModelEff()
    return self:GetModelEffByKey(ModelEffEnum.Main)
end

function LDreamTripUnitView:GetModelEffByKey(effectKey)
    if not self._modelEffMap then return end
    return self._modelEffMap[effectKey]
end
------------------------------------------------------------- 创建 LxEffectDp End


function LDreamTripUnitView:CreateSprite(targetObj,targetObjTrans,targetModel,targetEnum)
    local spriteRender = targetObj:GetComponent(typeOfSpriteRenderer)
    if not spriteRender then
        spriteRender = targetObj:AddComponent(typeOfSpriteRenderer)
    end
    spriteRender.sortingLayerName = LayerMaskNames.Object
    local sprite = require("LApp.component.res.LxSprite"):new(spriteRender)
    sprite:SetLoadedCallback(function()
        self:DoModelRootAni(targetObjTrans)
    end)
    sprite:SetSprite(targetModel)
    self._spriteMap[targetEnum] = sprite
    self._spriteRenderMap[targetEnum] = spriteRender
end

function LDreamTripUnitView:GetSpriteByKey(key)
    return self._spriteMap[key]
end

function LDreamTripUnitView:GetMainSprite()
    return self:GetSpriteByKey(SpriteEnum.Main)
end

function LDreamTripUnitView:GetTargetSprite()
    return self:GetSpriteByKey(SpriteEnum.Target)
end


return LDreamTripUnitView